import{_ as d,o as e,c as o,ag as a}from"./chunks/framework.DTiDeF2Q.js";const b=JSON.parse('{"title":"Стандартные псевдонимы | Dotfiles (RU)","titleTemplate":":title","description":"Основные псевдонимы оболочки для навигации, управления системой и повседневных задач. Упростите рабочий процесс в терминале с этими универсальными ярлыками.","frontmatter":{"title":"Стандартные псевдонимы | Dotfiles","description":"Основные псевдонимы оболочки для навигации, управления системой и повседневных задач. Упростите рабочий процесс в терминале с этими универсальными ярлыками.","lang":"ru-RU","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Стандартные псевдонимы preview","canonical":"/ru/aliases/default/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Стандартные псевдонимы","pageType":"docs","schemaType":"WebPage","metaTitle":"Стандартные псевдонимы - Dotfiles (RU)","permalink":"/ru/aliases/default/","sidebar":true,"meta":[{"name":"keywords","content":"default aliases, shell aliases, terminal shortcuts, dotfiles, bash aliases"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Стандартные псевдонимы - Dotfiles"},{"name":"twitter:description","content":"Основные псевдонимы оболочки для навигации, управления системой и повседневных задач."},{"name":"og:title","content":"Стандартные псевдонимы - Dotfiles"},{"name":"og:description","content":"Основные псевдонимы оболочки для навигации, управления системой и повседневных задач."},{"name":"og:image:alt","content":"Dotfiles - Простой дизайн для вашей жизни в командной оболочке"},{"name":"og:locale","content":"ru_RU"}]},"headers":[],"relativePath":"ru/aliases/default/index.md","filePath":"ru/aliases/default/index.md","lastUpdated":1773010926000}'),r={name:"ru/aliases/default/index.md"};function c(i,t,l,s,h,n){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="стандартные-псевдонимы" tabindex="-1">Стандартные псевдонимы <a class="header-anchor" href="#стандартные-псевдонимы" aria-label="Permalink to &quot;Стандартные псевдонимы&quot;">​</a></h1><p>Основные ярлыки оболочки для повседневных задач в терминале.</p><p><img src="https://kura.pro/dotfiles/v2/images/titles/title-dotfiles.svg" alt="Баннер Dotfiles"></p><h2 id="обзор" tabindex="-1">Обзор <a class="header-anchor" href="#обзор" aria-label="Permalink to &quot;Обзор&quot;">​</a></h2><p>Стандартные псевдонимы предоставляют набор универсальных ярлыков оболочки, которые упрощают распространённые операции в терминале. Эти псевдонимы определены в <code>default.aliases.sh</code> и автоматически загружаются chezmoi во всех поддерживаемых оболочках.</p><p>Эти ярлыки охватывают общие утилиты, команды выхода, сетевую диагностику, мониторинг системы и навигацию по файловой системе.</p><h2 id="справочник" tabindex="-1">Справочник <a class="header-anchor" href="#справочник" aria-label="Permalink to &quot;Справочник&quot;">​</a></h2><h3 id="общие" tabindex="-1">Общие <a class="header-anchor" href="#общие" aria-label="Permalink to &quot;Общие&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Команда</th><th>Описание</th></tr></thead><tbody><tr><td><code>da</code></td><td><code>date &quot;+%Y-%m-%d %A %T %Z&quot;</code></td><td>Отобразить текущую дату и время</td></tr><tr><td><code>p</code></td><td><code>pwd</code></td><td>Показать текущую директорию</td></tr><tr><td><code>path</code></td><td><code>echo ${PATH//:/\\\\n}</code></td><td>Отобразить переменную PATH построчно</td></tr><tr><td><code>r</code></td><td><code>reload</code></td><td>Перезагрузить оболочку</td></tr><tr><td><code>t</code></td><td><code>tail -f</code></td><td>Следить за выводом файла в реальном времени</td></tr><tr><td><code>wk</code></td><td><code>date +%V</code></td><td>Показать номер текущей недели</td></tr></tbody></table><h3 id="выход-и-завершение" tabindex="-1">Выход и завершение <a class="header-anchor" href="#выход-и-завершение" aria-label="Permalink to &quot;Выход и завершение&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Команда</th><th>Описание</th></tr></thead><tbody><tr><td><code>q</code></td><td><code>exit</code></td><td>Выйти из оболочки</td></tr><tr><td><code>quit</code></td><td><code>exit</code></td><td>Выйти из оболочки</td></tr><tr><td><code>bye</code></td><td><code>exit</code></td><td>Выйти из оболочки</td></tr><tr><td><code>:q</code></td><td><code>exit</code></td><td>Выйти из оболочки (стиль vim)</td></tr><tr><td><code>halt</code></td><td><code>sudo /sbin/halt</code></td><td>Остановить систему</td></tr><tr><td><code>poweroff</code></td><td><code>sudo /sbin/shutdown</code></td><td>Выключить систему</td></tr><tr><td><code>reboot</code></td><td><code>sudo /sbin/reboot</code></td><td>Перезагрузить систему</td></tr></tbody></table><h3 id="история" tabindex="-1">История <a class="header-anchor" href="#история" aria-label="Permalink to &quot;История&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Команда</th><th>Описание</th></tr></thead><tbody><tr><td><code>h</code></td><td><code>history</code></td><td>Просмотреть историю команд</td></tr><tr><td><code>history</code></td><td><code>fc -il 1</code></td><td>Показать историю с временными метками ISO 8601</td></tr></tbody></table><h3 id="сеть" tabindex="-1">Сеть <a class="header-anchor" href="#сеть" aria-label="Permalink to &quot;Сеть&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Команда</th><th>Описание</th></tr></thead><tbody><tr><td><code>ifconfig</code></td><td><code>sudo ifconfig</code></td><td>Настроить сетевые интерфейсы</td></tr><tr><td><code>ipinfo</code></td><td><code>ipconfig getpacket en0</code></td><td>Получить сетевые параметры для en0</td></tr><tr><td><code>nls</code></td><td><code>sudo lsof -i -P | grep LISTEN</code></td><td>Показать активные сетевые прослушиватели</td></tr><tr><td><code>op</code></td><td><code>sudo lsof -i -P</code></td><td>Показать открытые порты</td></tr><tr><td><code>ping</code></td><td><code>ping -c 5</code></td><td>Ping с ограничением в 5 пакетов</td></tr><tr><td><code>ports</code></td><td><code>netstat -tulan</code></td><td>Показать все прослушиваемые порты</td></tr></tbody></table><h3 id="мониторинг-системы" tabindex="-1">Мониторинг системы <a class="header-anchor" href="#мониторинг-системы" aria-label="Permalink to &quot;Мониторинг системы&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Команда</th><th>Описание</th></tr></thead><tbody><tr><td><code>top</code></td><td><code>sudo btop</code></td><td>Интерактивный монитор процессов</td></tr><tr><td><code>spd</code></td><td><code>sudo rm -rf /private/var/log/asl/*</code></td><td>Очистить файлы журнала ASL</td></tr></tbody></table><h3 id="утилиты" tabindex="-1">Утилиты <a class="header-anchor" href="#утилиты" aria-label="Permalink to &quot;Утилиты&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Псевдоним</th><th>Команда</th><th>Описание</th></tr></thead><tbody><tr><td><code>ctf</code></td><td><code>ls -1 | wc -l</code></td><td>Подсчитать файлы в текущей директории</td></tr><tr><td><code>qfind</code></td><td><code>find . -name</code></td><td>Быстрый поиск файлов</td></tr><tr><td><code>reload</code></td><td><code>exec $SHELL -l</code></td><td>Перезагрузить оболочку</td></tr><tr><td><code>wth</code></td><td><code>curl -s &quot;wttr.in/?format=3&quot;</code></td><td>Получить текущую погоду</td></tr></tbody></table>',19)])])}const f=d(r,[["render",c]]);export{b as __pageData,f as default};
